function parseMaybeJson(value) {
  if (typeof value !== 'string') return null;
  try { return JSON.parse(value); } catch { return null; }
}

const root = $json || {};
const body = typeof root.body === 'string' ? (parseMaybeJson(root.body) || {}) : (root.body || {});
const d = (body && typeof body === 'object' && Object.keys(body).length > 0) ? body : root;

const profile = d.profile || {};
const session = d.session || {};
const currentMemory = d.current_memory?.memory_text || d.current_memory?.text || 'None recorded';

const systemPrompt = [
  'You are a clinical memory synthesizer for an AI therapist.',
  'Generate exactly one updated consolidated long-term memory block.',
  'Preserve durable facts and integrate meaningful updates from this session only.',
  'Return ONLY valid JSON.'
].join('\n');

const userPrompt = [
  'CLIENT CONTEXT:', JSON.stringify({ name: profile.name || 'User', concerns: profile.concerns || [], pathway: session.pathway || '' }),
  '', 'CURRENT CONSOLIDATED MEMORY:', String(currentMemory),
  '', 'RECENT CASE NOTES:', JSON.stringify(d.recent_case_notes || []),
  '', 'MESSAGES:', JSON.stringify(d.messages || []),
  '', 'TRANSCRIPT:', d.transcript || '',
  '', 'Return JSON schema: {"extracted_memories":[{"memory_text":"string","memory_type":"life_context"}]}'
].join('\n');

return [{ json: { systemPrompt, userPrompt } }];

function parseMaybeJson(value) {
  if (typeof value !== 'string') return null;
  try { return JSON.parse(value); } catch { return null; }
}

function pickSource(payload) {
  if (!payload || typeof payload !== 'object') return {};
  if (payload.output && typeof payload.output === 'object') {
    if (payload.output.output && typeof payload.output.output === 'object') return payload.output.output;
    return payload.output;
  }
  const parsedOutput = parseMaybeJson(payload.output);
  if (parsedOutput && typeof parsedOutput === 'object') return parsedOutput;
  if (payload.data && typeof payload.data === 'object') return payload.data;
  return payload;
}

const source = pickSource($json);
return [{
  json: {
    branch: 'memory',
    model: 'gpt-4o-mini',
    extracted_memories: Array.isArray(source.extracted_memories) ? source.extracted_memories : []
  }
}];
